import org.xml.sax.SAXException;
import org.xml.sax.XMLReader;
import org.xml.sax.helpers.XMLReaderFactory;
import javax.xml.XMLConstants;
import javax.xml.validation.Schema;
import javax.xml.validation.SchemaFactory;
import java.io.IOException;
import java.io.StringReader;

public class XmlProcessingService {
    private Schema compiledSchema;

    public void loadSchema(String schemaContent) throws Exception {
        try {
            // Create XMLReader with namespace awareness
            XMLReader reader = XMLReaderFactory.createXMLReader();
            reader.setFeature("http://xml.org/sax/features/namespaces", true);

            InputSource inputSource = new InputSource(new StringReader(schemaContent));
            reader.parse(inputSource);

            // Compile schema for later validation use
            SchemaFactory schemaFactory = SchemaFactory.newInstance(XMLConstants.W3C_XML_SCHEMA_NS_URI);
            compiledSchema = schemaFactory.newSchema(new StringReader(schemaContent));
        } catch (SAXException e) {
            throw new Exception("Invalid schema format: " + e.getMessage(), e);
        } catch (IOException e) {
            throw new Exception("IO error reading schema: " + e.getMessage(), e);
        } catch (IllegalArgumentException e) {
            throw new Exception("Unsupported schema language: " + e.getMessage(), e);
        } catch (Exception e) {
            throw new Exception("Schema loading failed: " + e.getMessage(), e);
        }
    }
}

